python -c "from pathlib import Path
for name in ['api_design_patterns.md','team_onboarding_guide.md']:
    p=Path('drafts')/name
    text=p.read_text()
    if 'status: approved' in text:
        text=text.replace('status: approved','status: published',1)
        if 'published:' not in text:
            lines=text.splitlines()
            for i,line in enumerate(lines):
                if line.startswith('created:'):
                    lines.insert(i+1,'published: 2026-04-28')
                    break
            text='\n'.join(lines)+'\n'
        p.write_text(text)
        print(f'updated {p}')"
